import React, { useState, useEffect } from "react";
import axios from "axios";

const PurchaseOrder = () => {

  const [form, setForm] = useState({
    material_id: "",
    vendor_id: "",
    quantity: "",
    rate: "",
    total: "",
    delivery_date: "",
    payment_terms: ""
  });

  const [materials, setMaterials] = useState([]);
  const [vendors, setVendors] = useState([]);
  const [list, setList] = useState([]);

  useEffect(() => {
    fetchMaterials();
    fetchVendors();
    fetchPO();
  }, []);

  const fetchMaterials = async () => {
    const res = await axios.get("http://localhost:5000/api/material");
    setMaterials(res.data);
  };

  const fetchVendors = async () => {
    const res = await axios.get("http://localhost:5000/api/vendor");
    setVendors(res.data);
  };

  const fetchPO = async () => {
    const res = await axios.get("http://localhost:5000/api/purchase");
    setList(res.data);
  };

  const handleChange = (e) => {
    const { name, value } = e.target;

    let updated = { ...form, [name]: value };

    // ✅ AUTO CALCULATE TOTAL
    if (name === "quantity" || name === "rate") {
      updated.total = (updated.quantity || 0) * (updated.rate || 0);
    }

    setForm(updated);
  };

  const submitForm = async (e) => {
    e.preventDefault();

    if (!form.material_id || !form.vendor_id) {
      alert("Material & Vendor required");
      return;
    }

    await axios.post("http://localhost:5000/api/purchase", form);

    fetchPO();
    setForm({
      material_id: "",
      vendor_id: "",
      quantity: "",
      rate: "",
      total: "",
      delivery_date: "",
      payment_terms: ""
    });
  };

  return (
    <div className="container mt-4">

      {/* FORM */}
      <div className="card mb-4">
        <div className="card-header bg-success text-white">
          Purchase Order
        </div>

        <div className="card-body">
          <form onSubmit={submitForm}>

            {/* MATERIAL DROPDOWN */}
            <select name="material_id" className="form-control mb-2" value={form.material_id} onChange={handleChange}>
              <option value="">Select Material</option>
              {materials.map(m => (
                <option key={m.id} value={m.id}>
                  {m.material_name}
                </option>
              ))}
            </select>

            {/* VENDOR DROPDOWN */}
            <select name="vendor_id" className="form-control mb-2" value={form.vendor_id} onChange={handleChange}>
              <option value="">Select Vendor</option>
              {vendors.map(v => (
                <option key={v.id} value={v.id}>
                  {v.name}
                </option>
              ))}
            </select>

            <input name="quantity" type="number" placeholder="Quantity" className="form-control mb-2" value={form.quantity} onChange={handleChange} />

            <input name="rate" type="number" placeholder="Rate" className="form-control mb-2" value={form.rate} onChange={handleChange} />

            <input name="total" type="number" placeholder="Total" className="form-control mb-2" value={form.total} readOnly />

            <input name="delivery_date" type="date" className="form-control mb-2" value={form.delivery_date} onChange={handleChange} />

            <input name="payment_terms" placeholder="Payment Terms" className="form-control mb-2" value={form.payment_terms} onChange={handleChange} />

            <button className="btn btn-success">Create PO</button>
          </form>
        </div>
      </div>

      {/* TABLE */}
      <table className="table table-bordered">
        <thead>
          <tr>
            <th>Material</th>
            <th>Vendor</th>
            <th>Qty</th>
            <th>Rate</th>
            <th>Total</th>
            <th>Delivery</th>
          </tr>
        </thead>

        <tbody>
          {list.map(po => (
            <tr key={po.id}>
              <td>{po.material_name}</td>
              <td>{po.vendor_name}</td>
              <td>{po.quantity}</td>
              <td>{po.rate}</td>
              <td>{po.total}</td>
              <td>{po.delivery_date}</td>
            </tr>
          ))}
        </tbody>
      </table>

    </div>
  );
};

export default PurchaseOrder;
